{
  "name": "AtomoraCQ",
  "description": "High-fidelity prototype for AI-driven and Quantum-simulated carbon capture material discovery.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum WorkflowState {
  IDLE = 'idle',
  AI_FILTERING = 'ai-filtering',
  QUANTUM_SIMULATION = 'quantum-simulation',
  RESULTS = 'results'
}

export interface MaterialCandidate {
  id: string;
  name: string;
  energy: number;
  porosity: number;
  cost: 'Low' | 'Medium' | 'High';
}

export interface SimulationLog {
  timestamp: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Atom, 
  Zap, 
  Shield, 
  Wind, 
  FlaskConical, 
  Cpu, 
  Database, 
  BarChart3, 
  Download, 
  Moon, 
  Sun,
  Info,
  ChevronRight,
  Loader2,
  RefreshCcw,
  CheckCircle2
} from 'lucide-react';
import { WorkflowState, MaterialCandidate, SimulationLog } from './types';
import Sidebar from './components/Sidebar';
import MoleculeViewer from './components/MoleculeViewer';
import AIFilteringEngine from './components/AIFilteringEngine';
import QuantumSimulator from './components/QuantumSimulator';
import ResultsDashboard from './components/ResultsDashboard';
import TechnicalModal from './components/TechnicalModal';

const App: React.FC = () => {
  const [workflow, setWorkflow] = useState<WorkflowState>(WorkflowState.IDLE);
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [showInfo, setShowInfo] = useState(false);
  const [logs, setLogs] = useState<SimulationLog[]>([]);

  const addLog = (message: string, type: 'info' | 'success' | 'warning' | 'error' = 'info') => {
    setLogs(prev => [{
      timestamp: new Date().toLocaleTimeString(),
      message,
      type
    }, ...prev].slice(0, 50));
  };

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.classList.remove('bg-slate-50');
      document.body.classList.add('bg-slate-950');
    } else {
      document.documentElement.classList.remove('dark');
      document.body.classList.add('bg-slate-50');
      document.body.classList.remove('bg-slate-950');
    }
  }, [isDarkMode]);

  const initiateDiscovery = () => {
    setWorkflow(WorkflowState.AI_FILTERING);
    addLog("Initiating discovery pipeline...", "info");
    addLog("Loading Material Genome Database (1.2M entries)", "info");

    setTimeout(() => {
      setWorkflow(WorkflowState.QUANTUM_SIMULATION);
      addLog("AI Filtering complete: Top 100 candidates selected", "success");
      addLog("Spawning Quantum Molecular Simulation instances", "info");
    }, 3500);

    setTimeout(() => {
      setWorkflow(WorkflowState.RESULTS);
      addLog("Quantum simulation converged", "success");
      addLog("New Material Identified: QuantumMOF-X1", "success");
    }, 8000);
  };

  const resetPipeline = () => {
    setWorkflow(WorkflowState.IDLE);
    setLogs([]);
  };

  return (
    <div className={`min-h-screen flex transition-colors duration-300 ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
      <Sidebar workflow={workflow} />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-16 flex items-center justify-between px-8 border-b border-slate-200 dark:border-slate-800 glass z-20">
          <div className="flex items-center gap-3">
            <Atom className="w-8 h-8 text-cyan-400 animate-pulse-slow" />
            <div>
              <h1 className="font-bold text-xl tracking-tight">Atomora<span className="neonic-text">CQ</span></h1>
              <p className="text-xs text-slate-400 dark:text-slate-500 font-medium uppercase tracking-widest">Quantum Synthesis Lab</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={() => setShowInfo(true)}
              className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
              title="Technical Analysis"
            >
              <Info className="w-5 h-5 text-slate-400" />
            </button>
            <button 
              onClick={() => setIsDarkMode(!isDarkMode)}
              className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
            >
              {isDarkMode ? <Sun className="w-5 h-5 text-yellow-400" /> : <Moon className="w-5 h-5 text-indigo-400" />}
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 flex flex-col p-6 overflow-y-auto">
          {workflow === WorkflowState.IDLE && (
            <div className="flex-1 flex flex-col items-center justify-center space-y-8 animate-in fade-in zoom-in duration-500">
              <div className="relative">
                <div className="absolute inset-0 bg-cyan-500 blur-3xl opacity-20 rounded-full animate-pulse"></div>
                <Atom className="w-32 h-32 text-cyan-400 relative z-10 animate-float" />
              </div>
              <div className="text-center space-y-4 max-w-2xl">
                <h2 className="text-5xl font-extrabold tracking-tighter">
                  Accelerate <span className="neonic-text">Carbon Capture</span> Discovery
                </h2>
                <p className="text-slate-400 text-lg">
                  Using AI-driven Graph Neural Networks and Variational Quantum Eigensolver (VQE)
                  to find the next generation of Metal-Organic Frameworks.
                </p>
              </div>
              <button 
                onClick={initiateDiscovery}
                className="group relative px-8 py-4 bg-slate-900 dark:bg-slate-100 dark:text-slate-950 rounded-xl font-bold text-lg overflow-hidden transition-all hover:scale-105 hover:shadow-[0_0_20px_rgba(34,211,238,0.5)]"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-cyan-400 via-magenta-500 to-lime-400 opacity-0 group-hover:opacity-10 transition-opacity"></div>
                <div className="flex items-center gap-2">
                  Initiate Discovery <ChevronRight className="w-5 h-5 transition-transform group-hover:translate-x-1" />
                </div>
              </button>
            </div>
          )}

          {workflow === WorkflowState.AI_FILTERING && <AIFilteringEngine />}

          {workflow === WorkflowState.QUANTUM_SIMULATION && <QuantumSimulator />}

          {workflow === WorkflowState.RESULTS && (
            <div className="flex-1 flex flex-col gap-6 animate-in slide-in-from-bottom-8 duration-700">
              <div className="flex justify-between items-end">
                <div>
                  <h2 className="text-3xl font-bold neonic-text">Discovery Achieved</h2>
                  <p className="text-slate-400">QuantumMOF-X1 shows unprecedented CO₂ affinity.</p>
                </div>
                <button 
                  onClick={resetPipeline}
                  className="flex items-center gap-2 px-4 py-2 text-sm bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors border border-slate-700"
                >
                  <RefreshCcw className="w-4 h-4" /> Reset Lab
                </button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2">
                  <MoleculeViewer showBinding={true} />
                </div>
                <div className="space-y-6">
                  <ResultsDashboard />
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Logs Bar */}
        <div className="h-12 glass border-t border-slate-200 dark:border-slate-800 flex items-center px-4 gap-4 overflow-hidden">
          <div className="flex items-center gap-2 whitespace-nowrap text-xs font-mono opacity-60">
            <span className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse"></span>
            SYSTEM STATUS: {workflow.toUpperCase()}
          </div>
          <div className="flex-1 flex gap-6 overflow-hidden">
            {logs.slice(0, 3).map((log, i) => (
              <div key={i} className={`text-xs font-mono whitespace-nowrap transition-all flex items-center gap-2 ${
                log.type === 'success' ? 'text-lime-400' : 
                log.type === 'warning' ? 'text-orange-400' :
                log.type === 'error' ? 'text-rose-400' : 'text-slate-400'
              }`}>
                <span className="opacity-40">[{log.timestamp}]</span>
                {log.message}
              </div>
            ))}
          </div>
        </div>

        {showInfo && <TechnicalModal onClose={() => setShowInfo(false)} />}
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Database, Cpu, BarChart3, Wind, FlaskConical, History, Settings } from 'lucide-react';
import { WorkflowState } from '../types';

interface SidebarProps {
  workflow: WorkflowState;
}

const Sidebar: React.FC<SidebarProps> = ({ workflow }) => {
  const menuItems = [
    { id: 'discover', label: 'Discover', icon: FlaskConical, active: workflow === WorkflowState.IDLE },
    { id: 'materials', label: 'Materials Project', icon: Database, active: workflow === WorkflowState.RESULTS },
    { id: 'quantum', label: 'Quantum Logs', icon: Cpu, active: workflow === WorkflowState.QUANTUM_SIMULATION },
    { id: 'impact', label: 'Climate Impact', icon: Wind, active: false },
    { id: 'analytics', label: 'Market Analytics', icon: BarChart3, active: false },
  ];

  return (
    <aside className="w-20 lg:w-64 glass border-r border-slate-200 dark:border-slate-800 flex flex-col transition-all z-30">
      <div className="flex-1 py-8 flex flex-col gap-2">
        {menuItems.map((item) => (
          <button
            key={item.id}
            className={`flex items-center gap-4 px-6 py-3 transition-all relative group ${
              item.active 
                ? 'text-cyan-400 bg-cyan-400/5' 
                : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            {item.active && (
              <div className="absolute left-0 top-0 bottom-0 w-1 bg-gradient-to-b from-cyan-400 to-blue-500"></div>
            )}
            <item.icon className={`w-5 h-5 ${item.active ? 'drop-shadow-[0_0_8px_rgba(34,211,238,0.8)]' : ''}`} />
            <span className="hidden lg:block font-medium text-sm">{item.label}</span>
          </button>
        ))}
      </div>

      <div className="p-4 flex flex-col gap-2 mb-8">
        <button className="flex items-center gap-4 px-6 py-2 text-slate-500 hover:text-slate-300 transition-colors">
          <History className="w-5 h-5" />
          <span className="hidden lg:block text-sm">History</span>
        </button>
        <button className="flex items-center gap-4 px-6 py-2 text-slate-500 hover:text-slate-300 transition-colors">
          <Settings className="w-5 h-5" />
          <span className="hidden lg:block text-sm">Settings</span>
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { FlaskConical } from 'lucide-react';

interface MoleculeViewerProps {
  showBinding?: boolean;
}

const MoleculeViewer: React.FC<MoleculeViewerProps> = ({ showBinding = false }) => {
  const [co2Pos, setCo2Pos] = useState({ x: 100, y: 100 });
  const [bound, setBound] = useState(false);

  useEffect(() => {
    if (showBinding) {
      const timer = setTimeout(() => {
        setBound(true);
      }, 2000);
      return () => clearTimeout(timer);
    } else {
      setBound(false);
    }
  }, [showBinding]);

  return (
    <div className="glass rounded-2xl p-4 h-[450px] relative overflow-hidden flex items-center justify-center neonic-border group">
      <div className="absolute top-4 left-4 flex items-center gap-2">
        <FlaskConical className="w-4 h-4 text-cyan-400" />
        <span className="text-xs font-mono uppercase tracking-widest text-slate-500">
          Molecular Lattice Visualization: QuantumMOF-X1
        </span>
      </div>

      <svg width="100%" height="100%" viewBox="0 0 400 300" className="drop-shadow-2xl">
        {/* Lattice Background (MOF Nodes) */}
        <g opacity="0.4">
          {[...Array(9)].map((_, i) => (
            <React.Fragment key={i}>
              <circle 
                cx={100 + (i % 3) * 100} 
                cy={50 + Math.floor(i / 3) * 100} 
                r="15" 
                className="fill-slate-800 stroke-cyan-500 stroke-2 animate-pulse"
                style={{ animationDelay: `${i * 0.2}s` }}
              />
              {/* Bonds */}
              {i % 3 < 2 && (
                <line 
                  x1={115 + (i % 3) * 100} y1={50 + Math.floor(i / 3) * 100} 
                  x2={185 + (i % 3) * 100} y2={50 + Math.floor(i / 3) * 100} 
                  stroke="#334155" strokeWidth="2"
                />
              )}
              {i < 6 && (
                <line 
                  x1={100 + (i % 3) * 100} y1={65 + Math.floor(i / 3) * 100} 
                  x2={100 + (i % 3) * 100} y2={135 + Math.floor(i / 3) * 100} 
                  stroke="#334155" strokeWidth="2"
                />
              )}
            </React.Fragment>
          ))}
        </g>

        {/* Target Metal Node */}
        <g>
          <circle cx="200" cy="150" r="22" fill="url(#metalGradient)" className="animate-pulse" />
          <text x="200" y="156" textAnchor="middle" fill="white" fontSize="14" className="font-mono font-bold">Zr</text>
          <circle cx="200" cy="150" r="40" fill="none" stroke="rgba(34, 211, 238, 0.2)" strokeWidth="1" className="animate-ping" />
        </g>

        {/* CO2 Molecule */}
        <g className={`transition-all duration-[2000ms] ease-in-out ${bound ? 'translate-x-[150px] translate-y-[100px]' : 'translate-x-0 translate-y-0 animate-float'}`}>
          <g transform={`translate(${bound ? 50 : 20}, ${bound ? 50 : 20}) rotate(${bound ? 0 : 45})`}>
            {/* O=C=O */}
            <line x1="-20" y1="0" x2="20" y2="0" stroke="rgba(255, 255, 255, 0.3)" strokeWidth="4" />
            <circle cx="-25" cy="0" r="10" fill="#ef4444" stroke="white" strokeWidth="1" /> {/* Oxygen */}
            <circle cx="0" cy="0" r="12" fill="#475569" stroke="white" strokeWidth="1" />  {/* Carbon */}
            <circle cx="25" cy="0" r="10" fill="#ef4444" stroke="white" strokeWidth="1" />  {/* Oxygen */}

            {bound && (
              <g className="animate-pulse">
                <circle cx="0" cy="0" r="35" fill="none" stroke="#84cc16" strokeWidth="2" strokeDasharray="4" />
                <path d="M-40,0 L-50,-10 M-40,0 L-50,10" stroke="#84cc16" strokeWidth="2" fill="none" />
              </g>
            )}
          </g>
        </g>

        <defs>
          <linearGradient id="metalGradient" x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor="#22d3ee" />
            <stop offset="100%" stopColor="#3b82f6" />
          </linearGradient>
        </defs>
      </svg>

      <div className="absolute bottom-6 right-6 flex flex-col gap-1 items-end">
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-red-500"></div>
          <span className="text-[10px] text-slate-400 font-mono">Oxygen (O)</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-slate-500"></div>
          <span className="text-[10px] text-slate-400 font-mono">Carbon (C)</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-2 h-2 rounded-full bg-cyan-500"></div>
          <span className="text-[10px] text-slate-400 font-mono">Zirconium Node (Zr₆O₄)</span>
        </div>
      </div>

      {bound && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none">
          <div className="w-32 h-32 bg-lime-400/20 blur-3xl rounded-full animate-pulse"></div>
          <div className="absolute top-0 left-1/2 -translate-x-1/2 bg-lime-500 text-slate-950 px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-tighter">
            Binding Confirmed
          </div>
        </div>
      )}
    </div>
  );
};

export default MoleculeViewer;

import React, { useState, useEffect } from 'react';
import { Database, Loader2 } from 'lucide-react';

const AIFilteringEngine: React.FC = () => {
  const [progress, setProgress] = useState(0);
  const [currentId, setCurrentId] = useState('MOF-000000');
  const [count, setCount] = useState(1200000);

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress(p => {
        if (p >= 100) return 100;
        return p + 1.2;
      });
      setCount(c => {
        const next = c - 15000;
        return next < 100 ? 100 : next;
      });
      setCurrentId(`MOF-${Math.floor(Math.random() * 999999).toString().padStart(6, '0')}`);
    }, 40);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="flex-1 flex flex-col items-center justify-center space-y-10 animate-in fade-in duration-500">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-bold tracking-tight flex items-center justify-center gap-3">
          <Database className="w-8 h-8 text-magenta-500" />
          AI Filtering Engine
        </h2>
        <p className="text-slate-400">Screening Material Genome Database using Graph Neural Networks (GNN)</p>
      </div>

      <div className="w-full max-w-xl space-y-4">
        <div className="flex justify-between text-sm font-mono text-slate-500">
          <span>Filtering 1.2M+ Candidates</span>
          <span className="text-magenta-400">{Math.floor(progress)}% Complete</span>
        </div>
        <div className="h-4 w-full bg-slate-900 rounded-full overflow-hidden border border-slate-800 p-0.5">
          <div 
            className="h-full bg-gradient-to-r from-cyan-400 via-magenta-500 to-lime-400 rounded-full transition-all duration-100 ease-linear shadow-[0_0_15px_rgba(217,70,239,0.5)]"
            style={{ width: `${progress}%` }}
          ></div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="glass rounded-xl p-4 border-magenta-500/20">
            <div className="text-[10px] uppercase text-slate-500 font-bold mb-1">Current Signature</div>
            <div className="text-xl font-mono text-cyan-400">{currentId}</div>
          </div>
          <div className="glass rounded-xl p-4 border-magenta-500/20">
            <div className="text-[10px] uppercase text-slate-500 font-bold mb-1">Remaining Scope</div>
            <div className="text-xl font-mono text-magenta-400">{count.toLocaleString()}</div>
          </div>
        </div>
      </div>

      <div className="flex items-center gap-3 text-slate-500 animate-pulse">
        <Loader2 className="w-5 h-5 animate-spin" />
        <span className="text-sm font-medium tracking-wide">Refining Topological Descriptor Weights...</span>
      </div>
    </div>
  );
};

export default AIFilteringEngine;

import React, { useState, useEffect } from 'react';
import { Cpu, Zap } from 'lucide-react';

const QuantumSimulator: React.FC = () => {
  const [energyData, setEnergyData] = useState<number[]>([]);
  const [iteration, setIteration] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setIteration(i => i + 1);
      setEnergyData(prev => {
        const last = prev.length > 0 ? prev[prev.length - 1] : 0;
        // Simulating VQE convergence towards -12.45 Hartree
        const target = -12.45;
        const noise = (Math.random() - 0.5) * 0.1 * Math.exp(-prev.length / 10);
        const next = last + (target - last) * 0.2 + noise;
        return [...prev, next].slice(-50);
      });
    }, 100);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in duration-500">
      {/* Quantum Circuit Visualization */}
      <div className="glass rounded-2xl p-6 flex flex-col neonic-border border-blue-500/30">
        <div className="flex items-center justify-between mb-8">
          <h3 className="text-lg font-bold flex items-center gap-2">
            <Cpu className="w-5 h-5 text-blue-400" />
            Quantum Circuit Architecture
          </h3>
          <span className="text-xs font-mono px-2 py-1 bg-blue-500/10 text-blue-400 rounded">VQE Ansätz</span>
        </div>

        <div className="flex-1 flex flex-col justify-around min-h-[300px]">
          {['q0', 'q1', 'q2', 'q3'].map((q, i) => (
            <div key={q} className="relative flex items-center">
              <span className="w-8 font-mono text-sm text-slate-500">{q}</span>
              <div className="flex-1 h-0.5 bg-slate-700 relative">
                {/* Gates */}
                <div 
                  className="absolute left-[20%] -top-4 w-10 h-10 glass border border-blue-400/50 flex items-center justify-center rounded text-[10px] font-bold text-blue-400 animate-pulse"
                  style={{ animationDelay: `${i * 0.2}s` }}
                >
                  Ry(θ)
                </div>
                {i < 3 && (
                  <div className="absolute left-[50%] -top-1 bottom-[-45px] w-0.5 bg-blue-500/30 flex items-center justify-center">
                     <div className="w-4 h-4 rounded-full border-2 border-blue-400 bg-slate-900 z-10"></div>
                     <div className="absolute bottom-0 w-6 h-6 border-2 border-blue-400 rounded flex items-center justify-center text-[8px] font-bold bg-slate-900 z-10">X</div>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-8 text-center">
          <div className="text-sm font-mono text-slate-400 mb-2">
            |ψ⟩ = α|0011⟩ + β|1100⟩ + γ|0101⟩
          </div>
          <div className="text-[10px] uppercase text-slate-500 font-bold tracking-widest">
            State Probabilities: α=0.82, β=0.14, γ=0.04
          </div>
        </div>
      </div>

      {/* VQE Energy Convergence Graph */}
      <div className="glass rounded-2xl p-6 flex flex-col neonic-border border-lime-500/30">
        <div className="flex items-center justify-between mb-8">
          <h3 className="text-lg font-bold flex items-center gap-2">
            <Zap className="w-5 h-5 text-lime-400" />
            Energy Convergence
          </h3>
          <span className="text-xs font-mono text-lime-400">Iter: {iteration}</span>
        </div>

        <div className="flex-1 relative">
          <svg width="100%" height="240" viewBox="0 0 400 240" className="overflow-visible">
            {/* Grid */}
            <line x1="0" y1="220" x2="400" y2="220" stroke="#334155" strokeWidth="1" />
            <line x1="0" y1="20" x2="0" y2="220" stroke="#334155" strokeWidth="1" />

            {/* Target line */}
            <line x1="0" y1="180" x2="400" y2="180" stroke="#84cc16" strokeWidth="1" strokeDasharray="4" opacity="0.3" />

            {/* Plot Line */}
            <path 
              d={`M ${energyData.map((d, i) => `${(i / 50) * 400},${100 - (d + 5) * 10}`).join(' L ')}`}
              fill="none"
              stroke="#84cc16"
              strokeWidth="2"
              className="transition-all duration-100"
            />
            {/* Glow effect */}
            <path 
              d={`M ${energyData.map((d, i) => `${(i / 50) * 400},${100 - (d + 5) * 10}`).join(' L ')}`}
              fill="none"
              stroke="#84cc16"
              strokeWidth="6"
              strokeOpacity="0.1"
              className="transition-all duration-100 blur-sm"
            />
          </svg>
          <div className="absolute top-2 left-2 text-[10px] font-mono text-slate-500">Energy (Hartree)</div>
          <div className="absolute bottom-2 right-2 text-[10px] font-mono text-slate-500">Optimization Steps</div>
