        <div 
          key={i} 
          className="absolute animate-float-slow text-slate-400/20"
          style={{ 
            top: `${Math.random() * 100}%`, 
            left: `${Math.random() * 100}%`,
            animationDelay: `${i * -2}s`,
          }}
        >
          {i % 5 === 0 ? <Atom size={40} className="text-cyan-400/30" /> : 
           i % 5 === 1 ? <span className="text-xl font-mono text-magenta-400/30">|ψ⟩</span> :
           i % 5 === 2 ? <span className="text-2xl font-mono text-lime-400/30">|101⟩</span> :
           i % 5 === 3 ? <BrainCircuit size={30} className="text-blue-400/30" /> :
