        </div>
      ))}
      {[...Array(15)].map((_, i) => (
        <div 
          key={`rev-${i}`} 
          className="absolute animate-float-reverse text-slate-400/10"
          style={{ 
            bottom: `${Math.random() * 100}%`, 
            right: `${Math.random() * 100}%`,
            animationDelay: `${i * -3}s`,
          }}
