  );
};

const App: React.FC = () => {
  const [workflow, setWorkflow] = useState<WorkflowState>(WorkflowState.IDLE);
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [showInfo, setShowInfo] = useState(false);
  const [logs, setLogs] = useState<SimulationLog[]>([]);

  const addLog = (message: string, type: 'info' | 'success' | 'warning' | 'error' = 'info') => {
    setLogs(prev => [{
      timestamp: new Date().toLocaleTimeString(),
      message,
      type
    }, ...prev].slice(0, 50));
  };

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.classList.remove('bg-slate-50');
      document.body.classList.add('bg-slate-950');
    } else {
      document.documentElement.classList.remove('dark');
      document.body.classList.add('bg-slate-50');
      document.body.classList.remove('bg-slate-950');
    }
  }, [isDarkMode]);

  const initiateDiscovery = () => {
    setWorkflow(WorkflowState.AI_FILTERING);
    addLog("Initiating discovery pipeline...", "info");
    addLog("Loading Material Genome Database (1.2M entries)", "info");

    setTimeout(() => {
      setWorkflow(WorkflowState.QUANTUM_SIMULATION);
      addLog("AI Filtering complete: Top 100 candidates selected", "success");
    }, 3500);

    setTimeout(() => {
      setWorkflow(WorkflowState.RESULTS);
      addLog("Quantum simulation converged", "success");
      addLog("New Material Identified: QuantumMOF-X1", "success");
    }, 8000);
  };

  const resetPipeline = () => {
    setWorkflow(WorkflowState.IDLE);
    setLogs([]);
  };

  const getStatusLabel = (state: WorkflowState) => {
    switch (state) {
      case WorkflowState.IDLE: return { text: "QUANTUM SYNTHESIS STANDBY", color: "text-slate-400" };
      case WorkflowState.AI_FILTERING: return { text: "NEURAL GNN SCREENING...", color: "text-magenta-400" };
      case WorkflowState.QUANTUM_SIMULATION: return { text: "VQE COHERENCE OPTIMIZATION", color: "text-cyan-400" };
      case WorkflowState.RESULTS: return { text: "TARGET IDENTIFIED: X1-PROTOCOL", color: "text-lime-400" };
      case WorkflowState.IMPACT: return { text: "ECOLOGICAL IMPACT PROJECTION", color: "text-emerald-400" };
      case WorkflowState.ANALYTICS: return { text: "MARKET FEASIBILITY MAPPING", color: "text-blue-400" };
      case WorkflowState.CONFIG: return { text: "INFRASTRUCTURE OPTIMIZATION", color: "text-cyan-400" };
      default: return { text: "SYSTEM ACTIVE", color: "text-slate-400" };
    }
  };

  const status = getStatusLabel(workflow);

  return (
    <div className={`min-h-screen flex transition-colors duration-300 ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
      <FloatingBackground />
      <Sidebar workflow={workflow} setWorkflow={setWorkflow} />

      <main className="flex-1 flex flex-col relative overflow-hidden z-10">
        {/* Header */}
        <header className="h-16 flex items-center justify-between px-8 border-b border-slate-200 dark:border-slate-800 glass z-20">
          <div className="flex items-center gap-3">
            <Atom className="w-8 h-8 text-cyan-400 animate-pulse-slow" />
            <div>
              <h1 className="font-bold text-xl tracking-tight">
                <span className="neonic-logo">Atomora</span><span className="neonic-text">CQ</span>
              </h1>
              <p className="text-xs text-slate-400 dark:text-slate-500 font-medium uppercase tracking-widest">Quantum Synthesis Lab</p>
            </div>
          </div>

          <div className="flex items-center gap-6">
            <button 
              className="group flex items-center gap-2 px-4 py-2 border border-gold-500 bg-gold-500/10 rounded-xl hover:bg-gold-500/20 transition-all shadow-[0_0_15px_rgba(251,191,36,0.2)]"
              onClick={() => addLog("Sustainable Development Goal 13: Climate Action Activated", "success")}
            >
              <Globe className="w-4 h-4 text-gold-500 group-hover:rotate-12 transition-transform" />
              <span className="gold-text text-sm font-bold tracking-tight">SDG - 13 ACTION</span>
            </button>

            <div className="flex items-center gap-2">
              <button 
                onClick={() => setShowInfo(true)}
                className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
                title="Technical Analysis"
              >
                <Info className="w-5 h-5 text-slate-400" />
              </button>
