        </g>

        {/* CO2 Molecule with Dynamic Path - Centered at (200, 150) when bound */}
        <g 
          className="transition-all duration-[1200ms] ease-out"
          style={{ 
            transform: bound 
              ? 'translate(200px, 150px)' 
              : `translate(${200 + entryX}px, ${150 + entryY}px)` 
          }}
        >
          <g style={{ transform: `rotate(${bound ? 0 : entryRotation}deg)`, transition: 'transform 1200ms ease-out' }}>
            {/* O=C=O Molecule */}
            <line x1="-22" y1="0" x2="22" y2="0" stroke="rgba(255, 255, 255, 0.4)" strokeWidth="4" />
            <circle cx="-25" cy="0" r="10" fill="#ef4444" stroke="white" strokeWidth="1.5" />
            <circle cx="0" cy="0" r="13" fill="#334155" stroke="white" strokeWidth="1.5" />
            <circle cx="25" cy="0" r="10" fill="#ef4444" stroke="white" strokeWidth="1.5" />

            {bound && (
              <g className="animate-pulse">
                <circle cx="0" cy="0" r="42" fill="none" stroke="#84cc16" strokeWidth="2" strokeDasharray="5 5" />
                <path d="M-45,0 L-55,-10 M-45,0 L-55,10" stroke="#84cc16" strokeWidth="3" fill="none" />
                <path d="M45,0 L55,-10 M45,0 L55,10" stroke="#84cc16" strokeWidth="3" fill="none" transform="rotate(180)" />
              </g>
            )}
          </g>
        </g>

        <defs>
          <linearGradient id={`metalGradient-${metalSymbol}`} x1="0%" y1="0%" x2="100%" y2="100%">
            <stop offset="0%" stopColor={metalColor} />
            <stop offset="100%" stopColor="#0f172a" />
          </linearGradient>
        </defs>
      </svg>

      {/* Stats Overlay */}
      <div className="absolute bottom-8 left-8 flex flex-col gap-1">
        <span className="text-[10px] font-mono text-slate-500 uppercase tracking-widest">Molecular Velocity</span>
        <span className={`text-sm font-bold ${bound ? 'text-lime-400' : 'text-cyan-400'}`}>
          {bound ? '0.00 m/s (Stable)' : '42.8 m/s (In-Flight)'}
        </span>
      </div>

      <div className="absolute bottom-8 right-8 flex flex-col gap-2 items-end glass p-4 rounded-2xl border-slate-800">
        <div className="flex items-center gap-3">
          <div className="w-3 h-3 rounded-full bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]"></div>
          <span className="text-[10px] text-slate-300 font-mono font-bold uppercase tracking-widest">Oxygen</span>
        </div>
        <div className="flex items-center gap-3">
          <div className="w-3 h-3 rounded-full bg-slate-500 shadow-[0_0_8px_rgba(100,116,139,0.5)]"></div>
          <span className="text-[10px] text-slate-300 font-mono font-bold uppercase tracking-widest">Carbon</span>
        </div>
        <div className="flex items-center gap-3">
          <div className="w-3 h-3 rounded-full shadow-[0_0_8px_rgba(34,211,238,0.5)]" style={{ backgroundColor: metalColor }}></div>
          <span className="text-[10px] text-slate-300 font-mono font-bold uppercase tracking-widest">{metalSymbol} Site</span>
        </div>
      </div>

      {bound && (
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
          <div className="w-[350px] h-[350px] bg-lime-400/5 blur-[90px] rounded-full animate-pulse"></div>
          <div className="mt-72 bg-lime-500/10 border border-lime-500/30 text-lime-400 px-8 py-3 rounded-full text-[10px] font-black uppercase tracking-[0.4em] backdrop-blur-md shadow-[0_0_40px_rgba(132,204,22,0.15)] animate-in zoom-in duration-500">
            Adsorption Event: Success
          </div>
        </div>
      )}

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes spin-slow {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
          animation: spin-slow 20s linear infinite;
        }
      `}} />
    </div>
  );
};

