                <span className={`text-[8px] font-bold uppercase tracking-tighter ${selectedMaterial.id === m.id ? 'text-white' : 'text-slate-500'}`}>
                  {m.id}
                </span>
              </div>
              {selectedMaterial.id === m.id && (
                <div className="absolute bottom-0 left-0 right-0 h-1 shadow-[0_-2px_10px_rgba(255,255,255,0.2)]" style={{ backgroundColor: m.metalColor }}></div>
