          </div>
          <div>
            <h3 className="text-2xl font-black tracking-tight text-white">{selectedMaterial.name}</h3>
            <span className="text-[10px] font-mono text-slate-500 uppercase tracking-[0.2em]">{selectedMaterial.formula}</span>
