        <div className="grid grid-cols-2 gap-4">
          {metrics.map((m, i) => (
            <div key={i} className="bg-slate-900/40 rounded-2xl p-4 border border-slate-800 hover:border-slate-700 transition-colors">
              <div className="flex items-center gap-2 mb-1">
                <m.icon className={`w-3.5 h-3.5 ${m.color}`} />
                <span className="text-[9px] uppercase text-slate-500 font-bold tracking-wider">{m.label}</span>
              </div>
              <div className="text-lg font-black text-white">{m.value}</div>
            </div>
          ))}
