const FloatingBackground = () => {
  const particles = useMemo(() => {
    // Increased particle count to 60 for "medium" density
    return [...Array(60)].map((_, i) => {
      // Distribution: 35% Molecules (0), 35% Qubits (1), 15% Binary (2), 15% Atoms (3)
      const rand = Math.random();
      let type = 0;
      if (rand < 0.35) type = 0; // Molecule
      else if (rand < 0.70) type = 1; // Qubit
      else if (rand < 0.85) type = 2; // Binary
      else type = 3; // Atom icon

      return {
        id: i,
        top: `${Math.random() * 100}%`,
        left: `${Math.random() * 100}%`,
        delay: `${Math.random() * -45}s`,
        speed: i % 3 === 0 ? 'animate-float-slow' : i % 3 === 1 ? 'animate-float-medium' : 'animate-float-fast',
        type,
        size: Math.random() * 35 + 15,
        color: i % 4 === 0 ? '#22d3ee' : i % 4 === 1 ? '#d946ef' : i % 4 === 2 ? '#84cc16' : '#3b82f6'
      };
    });
  }, []);

  return (
    <div className="fixed inset-0 pointer-events-none overflow-hidden z-0 opacity-[0.05] dark:opacity-[0.10]">
      {particles.map((p) => (
        <div 
          key={p.id} 
          className={`absolute ${p.speed}`}
          style={{ 
            top: p.top, 
            left: p.left,
            animationDelay: p.delay,
          }}
        >
          {p.type === 0 && <BackgroundMolecule color={p.color} size={p.size} />}
          {p.type === 1 && <QubitVisual color={p.color} size={p.size} />}
          {p.type === 2 && <div className="font-mono font-black" style={{ color: p.color, fontSize: p.size / 2.5 }}>|{Math.random() > 0.5 ? '01' : '10'}⟩</div>}
          {p.type === 3 && <Atom size={p.size} style={{ color: p.color }} className="animate-spin-slow" />}
        </div>
      ))}

      {/* Dynamic dust/energy particles */}
      {[...Array(15)].map((_, i) => (
        <div 
          key={`fly-${i}`}
          className="absolute bg-white rounded-full blur-[1px] animate-float-fast"
          style={{
            width: '1px',
            height: '1px',
            top: `${Math.random() * 100}%`,
            left: `${Math.random() * 100}%`,
            animationDelay: `${i * -3}s`,
            opacity: 0.3
          }}
        />
      ))}
    </div>
  );
};

